class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.size();
        int res = 0;
        vector<int> count(26, 0);
        for (char c : s) count[c - 'a']++;
        for (int i = 0; i < n / 2; i++) {
            char c = s[i];
            if (count[c - 'a'] == 1) {
                res += n / 2 - i;
            } else {
                int j = n - 1;
                while (s[j] != c) j--;
                res += n - 1 - j;
                swap(s[j], s[n - 1]);
                count[c - 'a']--;
            }
            count[s[i] - 'a']--;
        }
        return res;
    }
};
```
